import './App.css';
import axios from 'axios';
import { useEffect, useState } from 'react';

function App() {
    const [listOfUsers, setListOfUsers] = useState([]);

    useEffect(() => {
        axios.get("http://localhost:3001/users").then((response) => {
            setListOfUsers(response.data);
        })
    }, []);

    const listUsers = listOfUsers.map((value, key) => 
        <tr key={key}>
            <td className="mt-1 text-sm/6 text-gray-700 sm:col-span-2 sm:mt-0">{value.username}</td>
            <td className="mt-1 text-sm/6 text-gray-700 sm:col-span-2 sm:mt-0">{value.email}</td>
        </tr>
    );

    return (
        <div className="App">
                <table class="table-auto">
                    <thead><tr>
                        <th>User</th>
                        <th>Email</th>
                    </tr></thead>
                    <tbody>
                        {listUsers}
                    </tbody>
                </table>
        </div>
    );
}

export default App;
